_NUM = re.compile(r"\d")
_REGEXES = [re.compile(r"\s*" + r"\S+".join(re.escape(p) for p in t.split("<*>")) + r"\s*")
            for t in TEMPLATES]

_spec = importlib.util.spec_from_file_location(
    "llm_functions_thunderbird", Path(__file__).with_name("llm_functions.py"))
